/**
 * The problem asks us to sequentially add edges to a graph such that every cycle's total weight remains even.
 * Since edge weights are either 0 or 1, the total weight of a cycle is even if and only if the number of edges with weight 1 in that cycle is even.
 *
 * This property relates to the concept of cycles in a graph and cycle spaces, particularly in the context of XOR sums or parity.
 *
 * Consider the graph structure modulo 2. An edge with weight 1 corresponds to a change of parity, and an edge with weight 0 does not.
 * The condition "every cycle's total weight is even" is equivalent to stating that the graph must be bipartite with respect to the parity induced by the weights.
 *
 * More formally, if we assign a value (0 or 1) to each node, say $d[i]$, such that for any edge $(u, v)$ with weight $w$, we have $d[u] \oplus d[v] = w$, then any cycle $v_1 - v_2 - \dots - v_k - v_1$ will have a total weight $\sum w_i = 0 \pmod 2$ (even) if and only if the graph is such that we can assign such distances $d[i]$.
 *
 * The condition "every cycle has even weight" is equivalent to saying that the graph formed by edges with weight 1 must be bipartite.
 * However, since we are dealing with weights 0 and 1, a more direct approach using Disjoint Set Union (DSU) with parity tracking is standard for this type of problem (often related to finding bases for cycle spaces or checking bipartiteness/parity consistency).
 *
 * We will use a DSU structure where for each node $i$, we store:
 * 1. `parent[i]`: The parent of $i$.
 * 2. `diff[i]`: The parity of the path weight from node $i$ to its root (`parent[i]`). `diff[i] = 0` means the path has even weight; `diff[i] = 1` means the path has odd weight.
 *
 * When processing an edge $(u, v)$ with weight $w$:
 * 1. Find the roots and path parities for $u$ and $v$:
 *    - $(root_u, parity_u)$
 *    - $(root_v, parity_v)$
 * 2. If $root_u == root_v$:
 *    - $u$ and $v$ are already in the same connected component. Adding the edge $(u, v, w)$ creates a cycle.
 *    - The path between $u$ and $v$ through the current tree structure has a total weight parity of $parity_u \oplus parity_v$.
 *    - The new cycle's total weight parity is $(parity_u \oplus parity_v) \oplus w$.
 *    - If this cycle parity is 1 (odd weight), the condition is violated, so we discard the edge.
 *    - If it is 0 (even weight), we accept the edge (it doesn't change the cycle parity constraint).
 * 3. If $root_u \neq root_v$:
 *    - Adding the edge merges two components. We accept the edge.
 *    - We unite $root_u$ and $root_v$ (e.g., set $parent[root_v] = root_u$).
 *    - We must update $diff[root_v]$: The new path from $root_v$ to $root_u$ is composed of:
 *        - Path $root_v \to v$ (parity $parity_v$)
 *        - Edge $v \to u$ (weight $w$)
 *        - Path $u \to root_u$ (parity $parity_u$)
 *        - The parity of the path $root_v \to root_u$ is $parity_v \oplus w \oplus parity_u$.
 *        So, we set $diff[root_v] = parity_u \oplus w \oplus parity_v$.
 *
 * We count the number of edges accepted.
 */
function solve(n, edges) {
    const parent = Array(n).fill(0).map((_, i) => i);
    // diff[i] stores the parity of the path weight from node i to its current root.
    // 0 means even weight, 1 means odd weight.
    const diff = Array(n).fill(0);
    let acceptedEdgesCount = 0;

    // DSU Find operation with path compression and parity update
    // Returns [root, parity_to_root]
    const find = (i) => {
        if (parent[i] === i) {
            return [i, 0];
        }
        // Recursive call to find root and parity of parent
        const [root, rootParity] = find(parent[i]);

        // Update path compression: i's new parent is root.
        parent[i] = root;

        // Update i's parity: The path from i to root is (i -> parent[i]) + (parent[i] -> root)
        // New diff[i] = (old diff[i]) XOR (rootParity from old parent)
        diff[i] = diff[i] ^ rootParity;

        return [root, diff[i]];
    };

    // DSU Union operation (implicitly handles acceptance/rejection)
    const union = (u, v, w) => {
        const [rootU, parityU] = find(u);
        const [rootV, parityV] = find(v);

        if (rootU !== rootV) {
            // Case 1: Different components, always accept the edge
            acceptedEdgesCount++;

            // Merge V's component into U's component (arbitrarily choose U as new root)
            parent[rootV] = rootU;

            // Calculate the parity of the path from rootV to rootU.
            // Path: rootV --(parityV)--> v --(w)--> u --(parityU)--> rootU
            // Path weight parity: parityV XOR w XOR parityU
            diff[rootV] = parityV ^ w ^ parityU;

            return true; // Edge accepted
        } else {
            // Case 2: Same component, check for cycle parity

            // Parity of the path between u and v through the existing tree: parityU XOR parityV
            const existingCycleParity = parityU ^ parityV;

            // New cycle parity = existing path parity XOR new edge weight w
            const newCycleParity = existingCycleParity ^ w;

            if (newCycleParity === 0) {
                // Cycle weight is even, accept the edge
                acceptedEdgesCount++;
            }
            // If newCycleParity === 1, discard the edge (it creates an odd cycle)
            return false; // Edge rejected or accepted (but didn't change structure)
        }
    };

    for (const [u, v, w] of edges) {
        union(u, v, w);
    }

    return acceptedEdgesCount;
}

